// CASA Log Content Preprocessor
// Detects JSON network log data in the query and extracts attack indicators.
// Produces a concise log_summary for the Router LLM and an attack_indicators
// array for the Investigation Scanner keyword matching.
// Prevents large JSON files from overflowing the Router's 4096-token context window.

const body = $input.first().json;
const rawQuery = body.body?.query || '';

// Indicator types produced by filter_casa.py — these map to investigation types
const KNOWN_INDICATORS = [
  'HIGH_VOLUME',       // vulnerability_exploitation
  'SYN_FLOOD_PATTERN', // vulnerability_exploitation
  'TTL_VARIANCE',      // vulnerability_exploitation
  'SLOW_DOS_PATTERN',  // vulnerability_exploitation
  'EPHEMERAL_SRC',     // vulnerability_exploitation
  'BEACONING_PATTERN', // beaconing
  'LARGE_TRANSFER',    // exfiltration
  'PORT_SCAN_SOURCE',  // lateral_movement
  'MANY_RESETS'        // lateral_movement
];

const foundIndicators = new Set();
let captureInfo = null;
let logSummary = null;

// Quick detection: is there JSON log data in the query?
const hasLogData = rawQuery.includes('"capture_summary"') ||
                   (rawQuery.includes('"indicators"') && rawQuery.includes('"flows"'));

if (hasLogData) {
  // Extract indicator types by direct substring search (avoids JSON.parse on huge strings)
  for (const ind of KNOWN_INDICATORS) {
    if (rawQuery.includes('"' + ind)) {
      foundIndicators.add(ind);
    }
  }

  // Extract capture_summary metadata
  const srcMatch = rawQuery.match(/"source_file"\s*:\s*"([^"]+)"/);
  const flagMatch = rawQuery.match(/"flagged_flows"\s*:\s*(\d+)/);
  const totalMatch = rawQuery.match(/"total_unique_flows_found"\s*:\s*(\d+)/);

  if (srcMatch || flagMatch) {
    captureInfo = {
      source_file: srcMatch ? srcMatch[1] : 'unknown',
      flagged_flows: flagMatch ? parseInt(flagMatch[1]) : 0,
      total_flows: totalMatch ? parseInt(totalMatch[1]) : 0
    };
  }

  if (foundIndicators.size > 0) {
    const indList = Array.from(foundIndicators).join(', ');
    const statsNote = captureInfo
      ? ` [${captureInfo.flagged_flows}/${captureInfo.total_flows} flows flagged]`
      : '';
    logSummary = `Network log${statsNote}. Attack indicators: ${indList}`;
  } else {
    logSummary = 'Network capture log detected (no flagged indicators found)';
  }
}

// Build a concise query for the Router LLM.
// Truncates raw query to avoid overwhelming the model context window,
// then appends the extracted indicator summary.
let routerQuery = rawQuery;
if (logSummary) {
  const textPart = rawQuery.substring(0, 300);
  const truncated = rawQuery.length > 300 ? textPart + ' [log data omitted]' : textPart;
  routerQuery = truncated + '\n\nLog data summary: ' + logSummary;
}

return [{
  json: {
    ...body,
    body: {
      ...(body.body || {}),
      query: routerQuery
    },
    original_query: rawQuery,
    log_summary: logSummary,
    attack_indicators: Array.from(foundIndicators),
    has_log_data: hasLogData && foundIndicators.size > 0,
    capture_info: captureInfo
  }
}];

const items = $input.all();
const results = [];

const VALID_TYPES = [
  'auth_anomaly', 'beaconing', 'exfiltration', 'lateral_movement',
  'privilege_escalation', 'persistence', 'ransomware',
  'insider_threat', 'vulnerability_exploitation'
];

const TYPE_KEYWORDS = {
  'auth_anomaly': ['failed login', 'brute force', 'credential', 'password', 'ssh login', 'authentication', '4625', '4624', 'logon failure'],
  'beaconing': ['beacon', 'c2', 'c&c', 'command and control', 'periodic', 'every 60', 'every 30', 'interval', 'callback', 'dns tunnel'],
  'exfiltration': ['exfiltration', 'exfil', 'data theft', 'large transfer', 'upload', 'google drive', 'dns txt', 'data leak'],
  'lateral_movement': ['lateral', 'pass-the-hash', 'psexec', 'rdp', 'smb', 'credential reuse', 'east-west', 'pivot'],
  'privilege_escalation': ['privilege escalation', 'privesc', 'uac bypass', 'token', 'setuid', 'sudo abuse', 'dll injection'],
  'persistence': ['persistence', 'registry run', 'scheduled task', 'service creation', 'backdoor', 'cron', 'autostart'],
  'ransomware': ['ransomware', 'ransom', 'encrypt', 'shadow copy', 'vssadmin', 'bcdedit', 'bitcoin'],
  'insider_threat': ['insider', 'policy violation', 'after hours', 'data hoarding', 'personal cloud', 'unauthorized access'],
  'vulnerability_exploitation': ['exploit', 'cve', 'vulnerability', 'sql injection', 'xss', 'rce', 'web shell', 'buffer overflow']
};

for (const item of items) {
  let domain = 'mixed';
  let investigation_type = 'general';
  const responseText = (item.json.response || '').trim();
  const query = ($('Webhook Trigger').item.json.body?.query || '').toLowerCase();

  try {
    let cleaned = responseText
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .replace(/^[^{]*/, '')
      .replace(/}[^}]*$/, '}');

    const parsed = JSON.parse(cleaned);
    domain = parsed.domain || 'mixed';
    investigation_type = parsed.investigation_type || 'general';

    if (!VALID_TYPES.includes(investigation_type) && investigation_type !== 'general') {
      const normalized = investigation_type.toLowerCase().replace(/-/g, '_');
      const match = VALID_TYPES.find(t => t === normalized || normalized.includes(t) || t.includes(normalized));
      investigation_type = match || 'general';
    }
  } catch (e) {
    let bestType = 'general';
    let bestScore = 0;
    const searchText = query + ' ' + responseText.toLowerCase();

    for (const [type, keywords] of Object.entries(TYPE_KEYWORDS)) {
      let score = 0;
      for (const kw of keywords) {
        if (searchText.includes(kw)) score++;
      }
      if (score > bestScore) {
        bestScore = score;
        bestType = type;
      }
    }

    if (bestScore > 0) {
      investigation_type = bestType;
      if (['beaconing'].includes(bestType)) domain = 'network';
      else if (['auth_anomaly', 'persistence', 'privilege_escalation'].includes(bestType)) domain = 'log';
      else domain = 'mixed';
    }
  }

  const logPrep = $('Log Preprocessor').first().json;
  results.push({
    json: {
      query: logPrep.original_query || $('Webhook Trigger').item.json.body?.query || '',
      domain: domain,
      investigation_type: investigation_type,
      router_raw: responseText,
      attack_indicators: logPrep.attack_indicators || [],
      has_log_data: logPrep.has_log_data || false,
      log_summary: logPrep.log_summary || null
    }
  });
}

return results;

// CASA Investigation Scanner v2
// Replaces the Switch node. Determines which sub-workflows to run.
//
// Uses the Router LLM's classification as the PRIMARY type,
// then scans keywords to find ADDITIONAL relevant types.
// Outputs one item per investigation type to execute.
//
// This is the ONLY path to sub-workflows — no more dual-path race.

const input = $input.first().json;
const routerType = (input.investigation_type || 'general').toLowerCase();
const query = (input.query || '').toLowerCase();
// Pre-extracted attack indicators from Log Preprocessor (e.g. PORT_SCAN_SOURCE, BEACONING_PATTERN)
const attackIndicators = (input.attack_indicators || []).map(i => i.toLowerCase());
// Combined search text: full query text + extracted indicator keywords
const searchText = query + ' ' + attackIndicators.join(' ');

// Keyword definitions for each investigation type
const investigationKeywords = {
  auth_anomaly: [
    'failed login', 'login fail', 'authentication fail', 'invalid password',
    'brute force', 'credential stuff', 'account lockout', 'locked out',
    'invalid user', 'unknown user', 'logon failure', 'ssh login',
    'failed ssh', 'rdp login', 'kerberos', 'ntlm', 'password spray',
    'mfa', 'multi-factor', '4625', '4624', '4771', '4776',
    'pam_unix', 'sshd', 'accepted publickey', 'accepted password',
    'failed password', 'invalid credentials', 'unauthorized access',
    'root login', 'sudo', 'su:', 'authentication error',
    'access denied', 'permission denied', 'logon type',
    '4740', '4720', '4726', '4728', '4732', 'account locked', 'login attempt', 'failed attempt', 'auth fail', 'authentication bypass', 'credential dump', 'credential harvest', 'golden ticket', 'kerberos ticket', 'dcsync', 'ntlm hash', 'impossible travel', 'pass the hash', 'pth'
  ],
  beaconing: [
    'beacon', 'c2', 'c&c', 'command and control', 'callback',
    'periodic', 'interval', 'heartbeat', 'dns tunnel', 'dns query',
    'domain age', 'newly registered', 'dga', 'domain generation',
    'jitter', 'sleep', 'implant', 'cobalt strike', 'metasploit',
    'reverse shell', 'outbound connection', 'suspicious domain',
    'external ip', 'known bad', 'threat intel', 'ioc',
    'every 60 seconds', 'every 30 seconds', 'regular interval',
    'nslookup', 'dns request', 'txt record', 'encoded dns',
    'beaconing_pattern', 'avg_interval', 'base64', 'base64 encoding', 'keepalive', 'keep-alive', 'remote access tool', 'anydesk', 'teamviewer', 'certutil', 'bitsadmin', 'fast flux', 'domain fronting', 'non-standard port', 'unusual port', 'http beacon', 'http tunnel', 'protocol tunnel', 'protocol tunneling'
  ],
  exfiltration: [
    'exfiltration', 'exfil', 'data theft', 'data leak', 'data loss',
    'large transfer', 'upload', 'google drive', 'dropbox', 'onedrive',
    'mega.nz', 'file share', 'bulk download', 'after hours',
    'off hours', 'unusual hour', '2am', '3am', '4am',
    'staging', 'archive', 'compress', 'zip', 'rar', '7z',
    'encrypted channel', 'outbound', 'egress', 'dlp',
    'sensitive file', 'confidential', 'proprietary', 'intellectual property',
    'usb', 'removable media', 'cloud storage', 'personal email',
    'large volume', 'bandwidth spike', 'data ratio',
    'large_transfer', 'ftp', 'sftp', 'ftp-data', 'smtp', 'data staging', 'stage data', 'staging folder', 'email harvesting', 'mail forwarding', 'mailbox', 'dns exfiltration', 'txt record', 'encrypted archive', 'screenshot', 'screen capture', 'clipboard', 'keylogger', 'network share data', 'mapped drive'
  ],
  lateral_movement: [
    'lateral', 'east-west', 'pivot', 'pass-the-hash', 'pass the hash',
    'pth', 'pass-the-ticket', 'overpass', 'psexec', 'wmic', 'wmi',
    'winrm', 'powershell remote', 'smb', 'admin share', 'ipc$',
    'c$', 'admin$', 'remote desktop', 'rdp', 'ssh to', 'ssh from',
    'credential reuse', 'same credential', 'multiple host',
    'multiple server', 'spread', 'moved to', 'hopping',
    'internal scan', 'port scan', 'network scan', 'nmap',
    'service enumeration', 'net view', 'net use',
    '4648', '4624 type 3', 'type 10', 'remote logon',
    'port_scan_source', 'many_resets', 'netbios', 'msrpc', 'mimikatz', 'bloodhound', 'sharphound', 'crackmapexec', 'impacket', 'dcom', 'mstsc', 'ntlm hash', 'overpass the hash', '3389', '445', '5985', '5986', 'session takeover', 'session hijack', 'vnc', 'mmc', 'scp'
  ],
  privilege_escalation: [
    'privilege escalation', 'privesc', 'uac bypass', 'uac',
    'token manipulation', 'token impersonation', 'setuid', 'suid',
    'sudo abuse', 'sudo', 'dll injection', 'dll hijack',
    'service exploit', 'named pipe', 'potato', 'juicy',
    'special privileges', '4672', '4673', '4674',
    'elevated process', 'admin token', 'runas',
    'access token', 'impersonate', 'security descriptor',
    'kernel exploit', 'local exploit', 'elevation of privilege', 'elevation', 'group policy', 'gpo', 'code injection', 'process injection', 'thread injection', 'process hollowing', 'eventvwr', 'fodhelper', 'golden ticket', 'silver ticket', 'kerberoast', 'asreproast', 'ntlm relay', 'relay attack', 'trust modification', 'setgid', 'privilege abuse'
  ],
  persistence: [
    'persistence', 'registry run', 'registry key', 'run key',
    'scheduled task', 'schtasks', 'service creation', 'new service',
    'backdoor', 'cron', 'crontab', 'autostart', 'startup folder',
    'boot record', 'bootkit', 'implant', 'web shell',
    'account creation', 'hidden account', 'ssh key',
    '7045', '4697', 'service install',
    'rootkit', 'dll hijacking', 'dll side-loading', 'dll sideloading', 'launchd', 'ld_preload', 'dylib', 'bits', 'bits job', 'at job', 'add user', 'net user', 'useradd', 'lnk file', 'shortcut modification', 'path interception', 'mbr', 'uefi', 'event triggered', 'hkcu run', 'hklm run'
  ],
  ransomware: [
    'ransomware', 'ransom', 'encrypt', 'encrypted', '.encrypted',
    'shadow copy', 'vssadmin', 'bcdedit', 'wbadmin', 'bitcoin',
    'ransom note', 'decrypt', 'recovery disabled',
    'file rename', 'mass rename', 'crypto', 'locker',
    'lockbit', 'ryuk', 'conti', 'revil', 'blackcat', 'alphv', 'cl0p', 'wiper', 'wipe disk', 'restore point', 'double extortion', 'data leak site', 'backup deletion', 'monero', 'file extension'
  ],
  insider_threat: [
    'insider', 'policy violation', 'after hours', 'off hours',
    'data hoarding', 'personal cloud', 'unauthorized access',
    'resignation', 'departing employee', 'competitor',
    'need to know', 'outside scope', 'bulk copy', 'usb',
    'print', 'printing', 'printscreen', 'forwarding rule', 'inbox rule', 'email forwarding', 'terminated', 'contractor', 'classified', 'confidential', 'unusual access pattern', 'anomalous access', 'vdi', 'virtual desktop', 'solicitation'
  ],
  vulnerability_exploitation: [
    'exploit', 'cve', 'vulnerability', 'sql injection', 'sqli',
    'xss', 'rce', 'remote code execution', 'web shell',
    'buffer overflow', 'command injection', 'deserialization',
    'upload vulnerability', 'lfi', 'rfi', 'path traversal',
    'scanning campaign', '500 error', 'aspx', 'jsp',
    'dos', 'ddos', 'denial of service', 'slowloris', 'slow http',
    'goldeneye', 'golden eye', 'hulk', 'r-u-dead-yet', 'rudy',
    'http flood', 'syn flood', 'connection exhaustion', 'slow_dos_pattern',
    'application layer attack', 'resource exhaustion', 'keep-alive attack',
    'service disruption', 'high_volume', 'syn_flood_pattern',
    'ttl_variance', 'ephemeral_src', 'shellcode', 'meterpreter', 'payload delivery', 'nikto', 'gobuster', 'ffuf', 'nuclei', 'exploit kit', 'exploit chain', 'log4j', 'log4shell', 'proxyshell', 'proxylogon', 'xxe', 'ssti', 'csrf', 'arbitrary code', 'memory corruption'
  ]
};

// Step 1: Always include the Router LLM's classification (if valid)
const matchedTypes = new Map();
const validTypes = Object.keys(investigationKeywords);

if (validTypes.includes(routerType)) {
  matchedTypes.set(routerType, {
    count: 100,  // High priority — LLM classified this
    keywords: ['[Router LLM classification]'],
    source: 'router'
  });
}

// Step 2: Scan query for additional keyword matches
for (const [type, keywords] of Object.entries(investigationKeywords)) {
  let matchCount = 0;
  const matchedKeywords = [];

  for (const keyword of keywords) {
    if (searchText.includes(keyword)) {
      matchCount++;
      matchedKeywords.push(keyword);
    }
  }

  if (matchCount > 0 && !matchedTypes.has(type)) {
    matchedTypes.set(type, {
      count: matchCount,
      keywords: matchedKeywords,
      source: 'keyword'
    });
  } else if (matchCount > 0 && matchedTypes.has(type)) {
    // Augment the Router's classification with keyword evidence
    const existing = matchedTypes.get(type);
    existing.count += matchCount;
    existing.keywords.push(...matchedKeywords);
  }
}

// Step 3: Build output items
const outputItems = [];
const types = Array.from(matchedTypes.keys());

if (types.length === 0) {
  // No Router classification and no keywords — default to auth_anomaly
  outputItems.push({
    json: {
      query: input.query,
      domain: input.domain || 'mixed',
      investigation_type: 'auth_anomaly',
      scan_mode: 'default_fallback',
      matched_types: ['auth_anomaly'],
      total_matches: 1,
      scan_note: 'No classification or keywords matched — running default auth_anomaly analysis'
    }
  });
} else {
  for (const type of types) {
    const info = matchedTypes.get(type);
    outputItems.push({
      json: {
        query: input.query,
        domain: input.domain || 'mixed',
        investigation_type: type,
        scan_mode: info.source === 'router' ? 'router_classified' : 'keyword_matched',
        matched_types: types,
        keyword_matches: info.keywords,
        match_count: info.count,
        total_matches: types.length,
        scan_note: `${types.length} investigation path(s): ${types.join(', ')}`
      }
    });
  }
}

return outputItems;

// CASA Results Collector & Merger v2
// Collects ALL sub-workflow results and merges into a unified data structure.
// This is the ONLY node that feeds the Overseer.

const items = $input.all();
const timestamp = new Date().toISOString();

const reports = [];
const allTechniques = [];
const allNistFunctions = [];
const allCisControls = [];
const allCoverageGaps = [];
const investigationTypes = [];
let originalQuery = '';
let highestRisk = 'LOW';

const riskOrder = { 'LOW': 0, 'MEDIUM': 1, 'HIGH': 2, 'CRITICAL': 3 };

for (const item of items) {
  const data = item.json;

  if (data.investigation_report) {
    reports.push({
      type: data.investigation_type || 'unknown',
      report: data.investigation_report,
      risk_level: data.risk_level || 'MEDIUM',
      confidence: data.confidence || 'MEDIUM'
    });
    investigationTypes.push(data.investigation_type || 'unknown');

    if ((riskOrder[data.risk_level] || 0) > (riskOrder[highestRisk] || 0)) {
      highestRisk = data.risk_level;
    }
  }

  // Deduplicate MITRE techniques by ID
  if (data.mitre_techniques) {
    for (const t of data.mitre_techniques) {
      if (!allTechniques.find(e => e.id === t.id)) {
        allTechniques.push(t);
      }
    }
  }

  // Deduplicate NIST functions
  if (data.nist_csf_functions) {
    for (const f of data.nist_csf_functions) {
      if (!allNistFunctions.includes(f)) {
        allNistFunctions.push(f);
      }
    }
  }

  // Deduplicate CIS controls
  if (data.cis_controls) {
    for (const c of data.cis_controls) {
      if (!allCisControls.find(e => e.control_id === c.control_id)) {
        allCisControls.push(c);
      }
    }
  }

  if (data.coverage_gaps) {
    for (const g of data.coverage_gaps) {
      if (!allCoverageGaps.includes(g)) {
        allCoverageGaps.push(g);
      }
    }
  }

  if (data.query && !originalQuery) {
    originalQuery = data.query;
  }
}

// Build a structured payload for the Overseer
const payload = {
  reports_count: reports.length,
  investigation_types: investigationTypes,
  highest_risk: highestRisk,
  original_query: originalQuery,
  combined_techniques_count: allTechniques.length,
  combined_nist_functions: allNistFunctions,
  combined_cis_controls_count: allCisControls.length,
  coverage_gaps_count: allCoverageGaps.length,
  // Full data for the Overseer
  reports: reports,
  mitre_techniques: allTechniques,
  nist_csf_functions: allNistFunctions,
  cis_controls: allCisControls,
  coverage_gaps: allCoverageGaps,
  query: originalQuery,
  timestamp: timestamp
};

return [{ json: payload }];

// CASA Final Report Formatter — Overseer Output
// Combines the Overseer's synthesis with structured data from the Results Collector

const overseerResponse = $input.first().json.response || '';
const collectorData = $('Results Collector').first().json;

const timestamp = new Date().toISOString();
const query = collectorData.original_query || collectorData.query || 'N/A';
const types = collectorData.investigation_types || [];
const highestRisk = collectorData.highest_risk || 'MEDIUM';
const techniques = collectorData.mitre_techniques || [];
const nistFunctions = collectorData.combined_nist_functions || collectorData.nist_csf_functions || [];
const cisControls = collectorData.cis_controls || [];
const coverageGaps = collectorData.coverage_gaps || [];
const reportsCount = collectorData.reports_count || 0;

// Risk and confidence from overseer text
function extractRisk(text) {
  const n = text.toLowerCase();
  if (n.includes('critical')) return 'CRITICAL';
  if (n.includes('high risk') || n.includes('high severity')) return 'HIGH';
  if (n.includes('medium risk') || n.includes('moderate')) return 'MEDIUM';
  if (n.includes('low risk')) return 'LOW';
  return highestRisk; // Use the collected highest risk as default
}

function extractConfidence(text) {
  const n = text.toLowerCase();
  if (n.includes('high confidence')) return 'HIGH';
  if (n.includes('low confidence')) return 'LOW';
  return 'MEDIUM';
}

const riskLevel = extractRisk(overseerResponse);
const confidence = extractConfidence(overseerResponse);

// Format MITRE techniques
function formatMitre(techs) {
  if (!techs || techs.length === 0) return '| No MITRE ATT&CK techniques identified.';
  return techs.map(t => {
    const covLine = t.coverage
      ? `|   Coverage: CAR=${t.coverage.car} Sigma=${t.coverage.sigma} ES_SIEM=${t.coverage.es_siem} Splunk=${t.coverage.splunk} Total=${t.coverage.total}`
      : '';
    return [
      `| ${t.id} | ${t.name} | ${(t.tactics || []).join(', ')} |`,
      `|   Description: ${t.description || ''}`,
      `|   Detection: ${t.detection || ''}`,
      covLine,
    ].filter(Boolean).join('\n');
  }).join('\n');
}

// Format NIST CSF sections from sub-reports
function extractNistSections() {
  const reports = collectorData.reports || [];
  const sections = new Set();
  for (const r of reports) {
    // Extract NIST sections from individual reports
    const nistMatch = r.report.match(/2\. INCIDENT CLASSIFICATION[\s\S]*?(?=3\. TECHNICAL)/m);
    if (nistMatch) sections.add(nistMatch[0].trim());
  }
  if (sections.size === 0) return '| See individual sub-workflow reports for NIST CSF mappings.';
  // Return the most comprehensive one (longest)
  return Array.from(sections).sort((a, b) => b.length - a.length)[0];
}

// Format CIS Controls from sub-reports
function extractCisSections() {
  const reports = collectorData.reports || [];
  const sections = new Set();
  for (const r of reports) {
    const cisMatch = r.report.match(/5\.6 CIS CONTROLS[\s\S]*?(?=6\. RECOMMENDED)/m);
    if (cisMatch) sections.add(cisMatch[0].trim());
  }
  if (sections.size === 0) return '| See individual sub-workflow reports for CIS Controls.';
  return Array.from(sections).sort((a, b) => b.length - a.length)[0];
}

// Build the unified report
const typeNames = {
  'auth_anomaly': 'Authentication Anomaly',
  'beaconing': 'Beaconing / C2',
  'exfiltration': 'Data Exfiltration',
  'lateral_movement': 'Lateral Movement',
  'privilege_escalation': 'Privilege Escalation',
  'persistence': 'Persistence',
  'ransomware': 'Ransomware',
  'insider_threat': 'Insider Threat',
  'vulnerability_exploitation': 'Vulnerability Exploitation',
  'general': 'General Security'
};

const analysisMode = reportsCount > 1
  ? `Comprehensive (${reportsCount} investigation paths analyzed: ${types.map(t => typeNames[t] || t).join(', ')})`
  : `Focused (${typeNames[types[0]] || types[0] || 'General'} investigation)`;

const report = `
================================================================================
CASA INVESTIGATION REPORT — OVERSEER SYNTHESIS
Generated: ${timestamp}
Frameworks: MITRE ATT&CK | NIST CSF 2.0 | CIS Controls v8.1.2 | MITRE CAR
================================================================================

1. EXECUTIVE SUMMARY
--------------------------------------------------------------------------------
| Query: ${query}
| Analysis Mode: ${analysisMode}
| Overall Risk Level: ${riskLevel}
| Confidence: ${confidence}
| MITRE Techniques (combined): ${techniques.length}
| NIST CSF Functions: ${nistFunctions.join(', ') || 'N/A'}
| CIS Controls: ${cisControls.length}
| Coverage Gaps: ${coverageGaps.length}

2. OVERSEER ANALYSIS
--------------------------------------------------------------------------------
${overseerResponse.split('\n').map(l => '| ' + l).join('\n')}

3. MITRE ATT&CK MAPPING (Combined)
--------------------------------------------------------------------------------
${formatMitre(techniques)}

4. NIST CSF 2.0 CLASSIFICATION
--------------------------------------------------------------------------------
${extractNistSections()}

5. CIS CONTROLS v8.1.2 RECOMMENDATIONS
--------------------------------------------------------------------------------
${extractCisSections()}

6. EVIDENCE CHAIN
--------------------------------------------------------------------------------
| Investigation Flow:
| 1. Query received and routed through CASA Investigation Scanner
| 2. ${reportsCount} investigation path(s) identified: ${types.join(', ')}
| 3. Each path ran specialized analysts → MITRE → NIST → CIS → PurpleTeam → Synthesizer
| 4. ${techniques.length} unique MITRE ATT&CK techniques identified across all paths
| 5. Results collected and deduplicated by Results Collector
| 6. Overseer performed cross-correlation and synthesis
| 7. Final report generated

================================================================================
END OF REPORT | CASA CyberAnalysis System — Overseer Synthesis | ${timestamp}
================================================================================
`.trim();

return [{
  json: {
    status: 'complete',
    investigation_report: report,
    risk_level: riskLevel,
    confidence: confidence,
    mitre_techniques: techniques,
    nist_csf_functions: nistFunctions,
    cis_controls: cisControls,
    coverage_gaps: coverageGaps,
    query: query,
    investigation_type: types.length > 1 ? 'comprehensive' : (types[0] || 'general'),
